local xmlparser = require "xmlparser"
local cjson = require "cjson"

local function parse_soap_request()
    local request_body = ngx.req.get_body_data()
    
    if not request_body then
        ngx.status = 400
        ngx.say("Missing request body")
        ngx.exit(400)
        return
    end
    
    local parser = xmlparser.new()
    parser:setEntityResolver(function(entityName)
        -- Handle entity references
        if entityName == "soapenv" then
            return "http://schemas.xmlsoap.org/soap/envelope/"
        end
        return nil
    end)
    
    local xml_doc, err = parser:parse(request_body)
    if not xml_doc then
        ngx.status = 400
        ngx.say("Invalid XML: " .. (err or "Unknown error"))
        ngx.exit(400)
        return
    end
    
    -- Extract SOAP envelope
    local soap_envelope = xml_doc:getElement("Envelope")
    if not soap_envelope then
        ngx.status = 400
        ngx.say("Missing SOAP Envelope")
        ngx.exit(400)
        return
    end
    
    -- Extract header and body
    local soap_header = soap_envelope:getElement("Header")
    local soap_body = soap_envelope:getElement("Body")
    
    -- Process SOAP header if exists
    local header_data = {}
    if soap_header then
        for _, child in ipairs(soap_header:getChildren()) do
            header_data[child:getTagName()] = child:getText()
        end
    end
    
    -- Process SOAP body
    local body_data = {}
    if soap_body then
        local body_children = soap_body:getChildren()
        for _, child in ipairs(body_children) do
            local child_name = child:getTagName()
            local child_text = child:getText()
            
            -- Handle nested elements
            local nested_data = {}
            for _, nested_child in ipairs(child:getChildren()) do
                nested_data[nested_child:getTagName()] = nested_child:getText()
            end
            
            if next(nested_data) then
                body_data[child_name] = nested_data
            else
                body_data[child_name] = child_text
            end
        end
    end
    
    -- Return parsed data
    return {
        header = header_data,
        body = body_data,
        envelope = soap_envelope
    }
end

